// simple_note/static/src/js/ethiopian_date.min.js
// Lightweight Ethiopian date conversion

export const EthiopicDate = {
    // Constants
    JD_EPOCH_OFFSET_AMETE_ALEM: -285019, // world creation
    JD_EPOCH_OFFSET_AMETE_MIHRET: 1723856, // era of mercy (Ethiopic)

    /**
     * Calculates the number of days in a given Ethiopian month.
     * @param {number} year - Ethiopian year
     * @param {number} month - Ethiopian month (1-13)
     * @returns {number} Days in month (30, or 5/6 for Pagume)
     */
    getDaysInMonth: function (year, month) {
        if (month >= 1 && month <= 12) {
            return 30;
        }
        if (month === 13) {
            return (year % 4 === 3) ? 6 : 5;
        }
        return 30; // Fallback
    },

    /**
     * Converts Gregorian Date object to Ethiopian date parts
     */
    fromGregorian: function (d) {
        // Use UTC methods to avoid timezone issues when converting
        var year = d.getUTCFullYear();
        var month = d.getUTCMonth() + 1;
        var day = d.getUTCDate();

        var a = Math.floor((14 - month) / 12);
        var y = year + 4800 - a;
        var m = month + 12 * a - 3;
        var jdn = day + Math.floor((153 * m + 2) / 5) + 365 * y + Math.floor(y / 4) - Math.floor(y / 100) + Math.floor(y / 400) - 32045;

        // Convert JDN to Ethiopic
        var r = (jdn - 1723856) % 1461;
        var n = (r % 365) + 365 * Math.floor(r / 1460);

        var ethYear = 4 * Math.floor((jdn - 1723856) / 1461) + Math.floor(r / 365) - Math.floor(r / 1460);
        var ethMonth = Math.floor(n / 30) + 1;
        var ethDay = (n % 30) + 1;

        return { year: ethYear, month: ethMonth, day: ethDay };
    },

    /**
     * Converts Ethiopian date parts to JS Date object (Gregorian UTC)
     */
    toGregorian: function (year, month, day) {
        // Convert Ethiopic to JDN
        var jdn = (1723856 + 365) + 365 * (year - 1) + Math.floor(year / 4) + 30 * month + day - 31;

        // JDN to Gregorian
        var l = jdn + 68569;
        var n = Math.floor((4 * l) / 146097);
        l = l - Math.floor((146097 * n + 3) / 4);
        var i = Math.floor((4000 * (l + 1)) / 1461001);
        l = l - Math.floor((1461 * i) / 4) + 31;
        var j = Math.floor((80 * l) / 2447);
        var resDay = l - Math.floor((2447 * j) / 80);
        l = Math.floor(j / 11);
        var resMonth = j + 2 - 12 * l;
        var resYear = 100 * (n - 49) + i + l;

        // Return UTC date
        return new Date(Date.UTC(resYear, resMonth - 1, resDay));
    }
};
